import java.math.BigDecimal;

public class OrderAmountValidator {
    // 合法金额范围：0.01元 ~ 1000000.00元，即1分 ~ 100000000分
    private static final int MIN_CENT = 1;
    private static final int MAX_CENT = 100_000_000;
    // 用字符串构造BigDecimal，避免精度问题
    private static final BigDecimal MIN_AMOUNT = new BigDecimal("0.01");
    private static final BigDecimal MAX_AMOUNT = new BigDecimal("1000000.00");
    private static final BigDecimal HUNDRED = new BigDecimal(100);

    public static boolean isValid(String amountStr) {
        // 1. 处理null和空白输入
        if (amountStr == null) {
            return false;
        }
        amountStr = amountStr.trim();
        if (amountStr.isEmpty()) {
            return false;
        }

        try {
            // 2. 用字符串构造BigDecimal，避免double精度问题
            BigDecimal amount = new BigDecimal(amountStr);

            // 3. 校验小数位数是否≤2
            int scale = amount.scale();
            if (scale < 0 || scale > 2) {
                return false;
            }

            // 4. 校验数值范围，用compareTo比较，避免equals的标度问题
            if (amount.compareTo(MIN_AMOUNT) < 0 || amount.compareTo(MAX_AMOUNT) > 0) {
                return false;
            }

            // 5. 转换为分单位整数，精确计算（已校验小数位≤2，乘以100后必为整数）
            int cent = amount.multiply(HUNDRED).intValue();

            // 6. 二次校验分单位的范围（双重保险）
            return cent >= MIN_CENT && cent <= MAX_CENT;
        } catch (NumberFormatException e) {
            // 非数值输入直接返回false
            return false;
        }
    }

    // 可选：提供转换为分的方法，方便业务使用
    public static int toCent(String amountStr) {
        if (!isValid(amountStr)) {
            throw new IllegalArgumentException("非法金额：" + amountStr);
        }
        return new BigDecimal(amountStr).multiply(HUNDRED).intValue();
    }

    // 测试用例验证
    public static void main(String[] args) {
        // 合法输入测试
        System.out.println(isValid("0.01")); // true
        System.out.println(isValid("0.1")); // true
        System.out.println(isValid("1")); // true
        System.out.println(isValid("1000000.00")); // true
        System.out.println(isValid("00.01")); // true（数值合法，前导零允许）
        System.out.println(isValid(".01")); // true（数值合法，无整数部分允许）
        System.out.println(isValid("1.23")); // true

        // 非法输入测试
        System.out.println(isValid("0.015")); // false（3位小数）
        System.out.println(isValid("0.005")); // false（3位小数）
        System.out.println(isValid("0.009999999999999999")); // false（小于0.01）
        System.out.println(isValid("1000000.001")); // false（超过最大值+3位小数）
        System.out.println(isValid("-0.01")); // false（负数）
        System.out.println(isValid("abc")); // false（非数值）
        System.out.println(isValid("")); // false（空字符串）
        System.out.println(isValid("  ")); // false（纯空白）
        System.out.println(isValid("0.00")); // false（小于0.01）
        System.out.println(isValid("1000000.01")); // false（超过最大值）
    }
}
```
