        if (rows == 0) {
            throw new InsufficientStockException("库存不足");
        }
    } catch (SQLException e) {
        throw new BizException("数据库操作失败", e);
    } catch (InsufficientStockException | ParamInvalidException e) {
        throw e; // 业务异常直接抛出，已继承BizException
    } catch (Exception e) {
        throw new BizException("库存扣减失败", e);
    }
}
